import type { Article } from '../../../common/types/law.types';

export const ARTICLES_CONST_MISIONES: Article[] = [
  { id: 'const-misiones-art-10', lawId: 'const-misiones', number: '10', title: '', text: `Es inviolable en el territorio de la Provincia el derecho que toda persona tiene de profesar su culto libre y públicamente según los dictados de su conciencia, sin más limitaciones que las impuestas por la moral, las buenas costumbres y el orden público. El Estado no podrá dictar leyes u otras medidas que restrinjan o protejan culto alguno. Nadie podrá ser obligado a declarar su religión.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-11', lawId: 'const-misiones', number: '11', title: '', text: `Todos los habitantes de la Provincia gozan del derecho de reunirse pacíficamente para tratar asuntos políticos, gremiales, económicos, religiosos, sociales, culturales o de cualquier otra índole, en locales cerrados, particulares o públicos, sin permiso previo. Sólo cuando las reuniones se realicen en lugares abiertos y públicos deberá preavisarse a la autoridad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-12', lawId: 'const-misiones', number: '12', title: '', text: `Los habitantes de la Provincia gozarán de la libertad de expresar sus pensamientos y opiniones por cualquier medio y recibir o suministrar toda clase de informaciones. Los abusos de estos derechos serán reprimidos por la justicia ordinaria o el jurado, conforme a la ley que dicte la Provincia. Esta no podrá dictar leyes u otras medidas que, so pretexto de sancionar los abusos restrinjan o limiten tales derechos, como tampoco tendientes a coartar la difusión o libre expresión de las ideas; ni impedir o dificultar el funcionamiento de los talleres de imprenta, difusoras radiales y demás medios idóneos para la propagación del pensamiento; ni clausurar los locales en que ellos funcionen.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-13', lawId: 'const-misiones', number: '13', title: '', text: `Se reconoce a cada habitante de la Provincia el derecho de tener y llevar armas para su defensa personal, conforme a las leyes que dicte la Legislatura reglamentando su ejercicio.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-14', lawId: 'const-misiones', number: '14', title: '', text: `Salvo el caso de flagrancia en delito o contravención, nadie puede ser detenido sin orden escrita de autoridad competente fundada en indicios serios sobre la existencia de un hecho punible y la presunta responsabilidad de su autor o partícipe. La detención no podrá prolongarse por más de veinticuatro horas sin ponerse al detenido a disposición del juez y notificársele la causa de su detención. La autoridad a cuyo cargo esté la custodia de un detenido está obligada, sin perjuicio de las medidas y precauciones asegurativas del caso, a llevarlo a la presencia de cualquier persona que lo requiera. El incumplimiento o negligente observancia de las obligaciones señaladas en la presente disposición, ocasionan al funcionario o empleado responsable la pérdida de su empleo, sin perjuicio de las sanciones penales que puedan corresponderle.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-15', lawId: 'const-misiones', number: '15', title: '', text: `Las cárceles de la Provincia serán sanas, limpias y adecuadas para facilitar la readaptación social de los detenidos, presos o reclusos. Bajo estas mismas condiciones, La Provincia creará institutos especiales para menores y mujeres, y establecimientos para encausados y contraventores. Ninguna detención o arresto se hará en cárceles de penados sino en locales destinados a ese objeto.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-16', lawId: 'const-misiones', number: '16', title: '', text: `Frente a cualquier decisión o acto arbitrario de la autoridad, en relación tanto a la persona como a los derechos de los habitantes de la Provincia, y ya se trate de una lesión jurídica consumada como de una amenaza inminente, proceden los recursos de hábeas corpus o de amparo a los fines de que cese el efecto de lo ya consumado o no se lleve a cabo lo amenazado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-17', lawId: 'const-misiones', number: '17', title: '', text: `Los recursos a que se refiere el artículo anterior podrán ser interpuestos por el interesado o cualquier persona, sin necesidad de observar formas procesales, ante cualquier juez letrado de primera instancia, sin distinción de fueros o circunscripciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-18', lawId: 'const-misiones', number: '18', title: '', text: `Tanto en el caso de hábeas corpus como en el de amparo de cualquier derecho, el trámite de recurso será breve y sumarísimo, siendo responsable el juez que en él entienda de toda dilación inconducente o injustificada. La legislación procesal deberá prescribir las normas de sustanciación del recurso, ajustándose estrictamente a las bases de amplitud y celeridad que esta Constitución establece.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-19', lawId: 'const-misiones', number: '19', title: '', text: `Para el juzgamiento de las causas criminales la Provincia implantará el juicio oral, público, continuo y contradictorio. A tal efecto la ley creará los tribunales colegiados de derecho que sean necesarios así como los cargos que deban complementarlos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-20', lawId: 'const-misiones', number: '20', title: '', text: `Las causas orales se fallarán en instancia única y sólo procederá el recurso de casación ante el Superior Tribunal de Justicia, limitado a los casos de violación de formas o errónea aplicación de la ley sustantiva.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-21', lawId: 'const-misiones', number: '21', title: '', text: `La acción penal en los delitos de acción pública corresponde al Estado sin perjuicio de la participación que se le concede a la víctima y al particular damnificado. Toda persona particularmente ofendida por un delito de los que dan lugar a la acción pública puede intervenir en el proceso como querellante particular en la forma que la ley establezca. Los damnificados por el delito pueden hacer valer en sede penal sus pretensiones resarcitorias o indemnizatorias. * Modificado por Ley IV - N° 60.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-22', lawId: 'const-misiones', number: '22', title: '', text: `La incomunicación de los detenidos no podrá prolongarse más de cuarenta y ocho horas. En caso de que resultare indispensable a los fines de la investigación, podrá ampliarse por un lapso igual, mediante decisión judicial motivada.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-23', lawId: 'const-misiones', number: '23', title: '', text: `El sumario criminal es secreto sólo para los extraños. En caso de evidente necesidad, que el juez motivará suficientemente, podrá decretarse el secreto total o parcial por un lapso prudencial para la investigación, y que en ningún caso podrá exceder de cinco días.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-24', lawId: 'const-misiones', number: '24', title: '', text: `La autoridad policial que se desempeñe en la investigación de un hecho presuntivamente delictuoso podrá adoptar todas las medidas que le competen a los fines del esclarecimiento de la verdad, pero no recibir declaración indagatoria a los imputados, salvo en presencia del abogado defensor.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-25', lawId: 'const-misiones', number: '25', title: '', text: `Nadie puede ser procesado más de una vez por el mismo hecho y en caso de duda se estará siempre a los más favorable al reo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-26', lawId: 'const-misiones', number: '26', title: '', text: `Nadie puede ser considerado responsable sin sentencia judicial firme que así lo declare. Mientras ello no ocurra, todo imputado de delito goza de la presunción constitucional de inocencia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-27', lawId: 'const-misiones', number: '27', title: '', text: `Si por vía de revisión de una causa criminal se declarase la inocencia de un condenado, estará a cargo de la Provincia la indemnización de los daños emergentes de la condena y su ejecución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-28', lawId: 'const-misiones', number: '28', title: '', text: `Ningún habitante de la Provincia puede ser penado sin juicio previo fundado en ley anterior al hecho del proceso. Los jueces no podrán ampliar por analogía las incriminaciones legales ni interpretar extensivamente la ley penal en contra del procesado. Siempre se aplicará, aun con efecto retroactivo, la ley penal más favorable al imputado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-29', lawId: 'const-misiones', number: '29', title: '', text: `Los derechos y garantías enumerados en la Constitución Nacional y los que ésta misma establece no serán entendidos como negación de otros no enumerados que hacen a la esencia de la democracia, al sistema republicano de gobierno, a la libertad, a la seguridad y a la dignidad humanas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-30', lawId: 'const-misiones', number: '30', title: '', text: `El trabajo es un derecho y un deber de carácter social. La Provincia promoverá la creación de fuentes de trabajo y asegurará al trabajador las condiciones económicas, morales y culturales para una existencia digna.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-32', lawId: 'const-misiones', number: '32', title: '', text: `Sin perjuicio de los derechos que la Constitución y leyes nacionales acuerden al trabajador, la legislación provincial establecerá la libre elección de la ocupación; la regulación y control de los trabajos nocturnos e insalubres; los de las mujeres y de los menores; la seguridad en el trabajo y el derecho a la vivienda higiénica y decorosa.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-33', lawId: 'const-misiones', number: '33', title: '', text: `En la Provincia los gremios podrán organizarse libre y democráticamente sin más requisitos que la inscripción en un registro especial; podrán concertar contratos colectivos de trabajo y recurrir a la conciliación y arbitraje.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-34', lawId: 'const-misiones', number: '34', title: '', text: `Los sindicatos inscriptos no serán intervenidos ni sus locales clausurados sino por resolución judicial fundada en ley. Queda establecida la protección para el trabajador que ejerza cargos directivos en sus organizaciones sindicales o que invista representación conferida por éstas. La ley reglamentará esta protección asegurando el ejercicio de sus funciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-35', lawId: 'const-misiones', number: '35', title: '', text: `Todos los trabajadores de la Provincia, públicos o privados, tendrán derecho al seguro social integral e irrenunciable. A este fin se coordinará la legislación provincial con la nacional tendiente a la creación de organismos con autonomía financiera y económica, administrados por los interesados con participación del Estado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-36', lawId: 'const-misiones', number: '36', title: '', text: `Tanto las organizaciones gremiales como los trabajadores gozarán de gratuidad en las tramitaciones ante la justicia laboral y organismos administrativos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-37', lawId: 'const-misiones', number: '37', title: '', text: `La Ley asegurará: 1. Protección integral de la familia, procurándole los medios que le sean necesarios para el cumplimiento de sus funciones espirituales, culturales, económicas y sociales. 2. El amparo a la maternidad, a la infancia, minoridad, incapacidad y a la ancianidad de quienes carecen de familia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-38', lawId: 'const-misiones', number: '38', title: '', text: `Toda mujer que esté por dar a luz o haya dado a luz, todo anciano, todo discapacitado y todo menor de edad que se encuentren en estado de desamparo, serán protegidos por el Estado. A tal efecto la ley creará los organismos que asumirán esas tareas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-39', lawId: 'const-misiones', number: '39', title: '', text: `La Provincia garantizará la atención de la salud de la población, a cuyo fin la Legislatura dictará la ley sanitaria correspondiente que asegure la asistencia médica integral, preventiva y asistencial. A los efectos de cumplir más acabadamente estas obligaciones, el gobierno podrá por medio de convenios, comprometer su colaboración con la Nación, con otras provincias, asociaciones profesionales, entidades mutuales y cooperativas. La actividad de los profesionales del arte de curar debe considerarse como función social y regirse por leyes y disposiciones especiales que se dicten al respecto.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-40', lawId: 'const-misiones', number: '40', title: '', text: `La libertad de enseñar y de aprender las ciencias y las artes es un derecho que no podrá coartarse con medidas limitativas de ninguna especie. Es libre la investigación científica. La Cámara de Representantes proveerá por ley el establecimiento de un sistema de educación que contemple primordialmente la instruccción primaria y secundaria, y organizará la instrucción especial y superior.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-41', lawId: 'const-misiones', number: '41', title: '', text: `Las leyes que organicen y reglamente la educación se sujetarán a los principios y reglas siguientes: 1. La educación primaria es común y obligatoria en las condiciones y bajo las penas que la ley establezca. En las escuelas, institutos u organismos del Estado es, además, gratuita e integral. 2. Será de caracteres fundamentalmente nacional y específicamente regional, y tendrá como finalidad capacitar para dar satisfacción a las necesidades individuales y colectivas de la vida real, orientándose a formar ciudadanos aptos para la vida democrática y para la convivencia humana con sentido de solidaridad social. Juntamente con la enseñanza primaria, secundaria y especial, se impartirán conocimientos prácticos, relacionados con los sistemas cooperativos, con las actividades agrotécnicas e industriales, según la preponderancia de las mismas en los respectivos lugares. 3. Podrá ser recibida en escuelas, fiscales o particulares, o en el hogar. El Estado reconoce el derecho de todos a elegir libremente la escuela que corresponda a su ideal educativo. Cualquier persona o entidad podrá fundar y mantener establecimientos de enseñanza conforme a las leyes que reglamenten su funcionamiento. 4. La Provincia creará el seguro de enseñanza primaria, secundaria y universitaria, y asegurará una efectiva igualdad de oportunidades mediante el otorgamiento de becas y sistemas de créditos complementarios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-42', lawId: 'const-misiones', number: '42', title: '', text: `No se reconocerán más títulos o diplomas habilitantes para el ejercicio de una profesión u oficio que los expedidos por los organismos debidamente autorizados por las leyes nacionales y las de esta Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-43', lawId: 'const-misiones', number: '43', title: '', text: `La organización y dirección técnica y administrativa de la educación, excepto la universitaria, estará a cargo de un Consejo General de Educación autónomo compuesto de: un director general de educación, docente que ejercerá su presidencia, y cuatro vocales. El presidente y dos de los vocales serán nombrados por el Poder Ejecutivo con acuerdo de la Cámara de Representantes y los restantes elegidos por los docentes en actividad dependientes de la repartición. Durarán cuatro años en sus funciones, son reelegibles y sólo podrán ser removidas por el jurado de enjuiciamiento por las causas y de acuerdo al procedimiento establecido en el artículo 158 de esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-44', lawId: 'const-misiones', number: '44', title: '', text: `La ley creará consejos escolares departamentales, estableciendo su organización, atribuciones y deberes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-45', lawId: 'const-misiones', number: '45', title: '', text: `La ley determinará las rentas propias de la educación de modo que asegure los recursos necesarios para su sostenimiento, difusión y mejoramiento. En ningún caso la contribución del Tesoro de la Provincia para el fomento de la educación pública será inferior al veinte por ciento del total de las rentas generales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-46', lawId: 'const-misiones', number: '46', title: '', text: `La administración y disposición de los bienes y rentas escolares estarán a cargo del Consejo General de Educación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-47', lawId: 'const-misiones', number: '47', title: '', text: `La ley establecerá en el Estatuto del Docente, los deberes del personal dependiente del Consejo General de Educación afectado a la enseñanza o que colabore directamente en esta funciones con sujeción a normas pedagógicas, y le asegurará, sin perjuicio de los reconocidos por otras leyes, los siguientes derechos básicos: estabilidad, ascenso, traslado, vacaciones, estado docente, participación en el gobierno escolar, perfeccionamiento cultural y técnico, jubilación, asistencia social, agremiación y los que contribuyan a la dignificación de la función docente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-48', lawId: 'const-misiones', number: '48', title: '', text: `El régimen electoral para la Provincia será establecido por la ley, que deberá ajustarse a lo siguiente: 1. La representación política tiene por base la población. 2. El sufragio es universal, directo, secreto y obligatorio. 3. Son electores los ciudadanos, de ambos sexos, inscriptos en el registro cívico de la Nación y domiciliados en la Provincia. Cuando el registro cívico de la Nación no se ajuste a los principios de esta Constitución y leyes provinciales para el ejercicio del sufragio, la ley dispondrá la formación del registro cívico de la Provincia, bajo la dirección del Tribunal Electoral. 4. La Provincia constituye un distrito electoral único para todos los actos electorales que no tengan un régimen especial creado por esta Constitución. 5. El sistema electoral que regirá para la integración de los cuerpos colegiados deberá conceder, bajo pena de nulidad, representación a la minoría o minorías, que no podrá ser inferior al tercio del total. 6. Toda elección se hará por lista de candidatos oficializada por el Tribunal Electoral. El orden de colocación de los candidatos en la lista oficializada determinará la proclamación de los que resultaren electos. 7. Los electores no podrán ser detenidos veinticuatro horas antes ni después de cerrado el acto eleccionario. A la hora fijada, cada mesa receptora de votos practicará el escrutinio provisional. 8. Durante la elección, en el radio del comicio, no habrá más autoridad que la del presidente del mismo, cuyas órdenes y resoluciones deberán cumplir las fuerzas de seguridad y los ciudadanos. 9. Los partidos actuantes podrán designar fiscales en todas y en cada una de las mesas y ante el Tribunal Electoral. 10. No podrán votar los soldados pertenecientes a las fuerzas armadas ni los agentes de las seguridad nacionales y provinciales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-49', lawId: 'const-misiones', number: '49', title: '', text: `El Tribunal electoral, que tendrá carácter permanente, estará integrado por un miembro del Superior Tribunal de Justicia, un juez letrado y un miembro del ministerio público con asiento en la capital de la Provincia, designados por sorteo. El Tribunal Electoral funcionará en el local de la Legislatura bajo la presidencia del primero y tendrá las atribuciones que la ley establezca.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-50', lawId: 'const-misiones', number: '50', title: '', text: `El Estado provincial, mediante su legislación, formulará planeamientos para el desarrollo económico, con la colaboración de productores, trabajadores, empresarios y consumidores, en los modos y dentro de los límites que la ley fije.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-51', lawId: 'const-misiones', number: '51', title: '', text: `En el territorio de la Provincia la propiedad es inviolable y cumple una función social. La expropiación será calificada por ley especial y previamente indemnizada.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-52', lawId: 'const-misiones', number: '52', title: '', text: `Se dictará la ley de planeamiento provincial, de carácter regional, que fijará, con la participación activa de todos los grupos sociales y económicos, los programas para el pleno y armónico desarrollo de la economía y la cultura de la Provincia de Misiones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-53', lawId: 'const-misiones', number: '53', title: '', text: `La tierra actualmente en el patrimonio de la Provincia y la que en cualquier forma se adquiera en el futuro, deberá ser colonizada mediante entrega en propiedad de lotes que constituyan una unidad económica familiar, cuya superficie fijará la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-54', lawId: 'const-misiones', number: '54', title: '', text: `La ley reglamentará la colonización oficial o privada, sobre las siguientes bases: 1. Distribución por unidades económicas del tipo familiar, de acuerdo a su calidad y destino, evitando el minifundio. 2. Explotación directa y racional por el adjudicatario. 3. Adjudicación preferencial a grupos organizados en cooperativas. 4. Trámite sumario para el otorgamiento de los títulos, una vez cumplidas las exigencias legales. 5. Otorgamiento de crédito oficial con destino a la vivienda y producción.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-55', lawId: 'const-misiones', number: '55', title: '', text: `Se dictarán las leyes necesarias para instaurar una reforma agraria que propicie el acceso del hombre a la propiedad de la tierra, el fortalecimiento de la familia campesina y la vigorización de la economía agraria.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-56', lawId: 'const-misiones', number: '56', title: '', text: `El bosque será protegido con el fin de asegurar su explotación racional y lograr su mejor aprovechamiento social. La Ley asegurará la reforestación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-57', lawId: 'const-misiones', number: '57', title: '', text: `Se dictarán leyes especiales con los siguientes fines: 1. Conservación y mejoramiento de los suelos, de la flora y de la fauna. 2. Creación de escuelas especializadas para la educación agraria integral. 3. Régimen de crédito agrario tendiente a facilitar la explotación de la tierra y el afincamiento de la familia. 4. Seguro agrario obligatorio. 5. Promoción de la vivienda digna e higiénica para el trabajador rural.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-58', lawId: 'const-misiones', number: '58', title: '', text: `La Provincia tiene la plenitud del dominio, imprescriptible e inalienable, sobre las fuentes naturales de energía existentes en el territorio. Es facultad de la Provincia realizar por sí o convenir con la Nación o con otras provincias su explotación, cateo y extracción, así como su explotación, industrialización, distribución y comercialización, fijando de común acuerdo el monto de la regalía o contribución por percibir.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-59', lawId: 'const-misiones', number: '59', title: '', text: `Los servicios públicos corresponden originariamente a la Provincia o a los municipios y se propenderá a que la explotación de los mismos sea efectuada por el Estado, entes autárquicos o autónomos o cooperativas de usuarios en los que podrán intervenir las entidades públicas. E las localidades o centros de menor importancia podrá otorgarse la concesión a pequeñas empresas o a particulares, debiéndose ajustar la explotación a lo que determine la ley. Los de transporte terrestre o de la navegación por líneas regulares podrán concederse a empresas privadas o a cooperativas, pero dicha concesión deberá ser aprobada por la ley. También se podrán celebrar acuerdos con la Nación, otros estados provinciales o municipios para su explotación. La ley determinará la forma de explotación de los servicios públicos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-60', lawId: 'const-misiones', number: '60', title: '', text: `Las entidades gremiales y sindicales, cooperativas y asociaciones de productores y consumidores intervendrán en la defensa de la producción en relación al consumo y las necesidades de inversión.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-61', lawId: 'const-misiones', number: '61', title: '', text: `La Provincia, dentro de los derechos y garantías asegurados en esta Constitución, podrá controlar, tomar a su cargo o destinar para cooperativas o entidades similares, cuando el bien común lo exija, aquellas actividades en que predomine el interés público y en que la iniciativa privada sea insuficiente, monopolista o privilegiada.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-62', lawId: 'const-misiones', number: '62', title: '', text: `La Provincia reconoce la función social del cooperativismo. Promoverá y favorecerá su incremento por los medios más idóneos y asegurará su carácter y finalidades y facilitará el acceso directo de las cooperativas de producción a los mercados consumidores nacionales y extranjeros.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-63', lawId: 'const-misiones', number: '63', title: '', text: `El Estado provincial estimulará el aumento real del ahorro hasta niveles óptimos, haciéndole cumplir su función económico-social a través de la capitalización básica en la Provincia y asegurando su inembargabilidad. Regulará y controlará los sistemas de crédito y reprimirá el interés usurario.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-64', lawId: 'const-misiones', number: '64', title: '', text: `La Provincia creará bancos como entidades estatales o mixtas, debiendo en este último caso tener la mayoría absoluta del capital. Estará representada en el gobierno del banco únicamente por los directores nombrados por el Poder Ejecutivo, con acuerdo de la Legislatura. También propenderá a la creación o radicación de nuevos bancos en su territorio, especialmente los cooperativos y de fomento agrarioindustrial.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-65', lawId: 'const-misiones', number: '65', title: '', text: `El Estado promoverá y fomentará por ley u otras medidas la radicación de industrias de elaboración de materias primas en las zonas de producción.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-65', lawId: 'const-misiones', number: '65', title: '', text: `El Estado promoverá y fomentará por ley u otras medidas la radicación de industrias de elaboración de materias primas en las zonas de producción.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-67', lawId: 'const-misiones', number: '67', title: '', text: `El gobierno de la Provincia provee a los gastos de su gestión con los fondos del Tesoro Provincial formando: con el producido de la actividad económica del Estado, de las contribuciones permanentes y transitorias que la Legislatura establezca, de la venta y locación de las propiedades fiscales; de los productos, frutos y rentas de otros bienes de su pertenencia; de la participación que le corresponde en impuestos fijados por la Nación, de los servicios que prestare y de los empréstitos y demás operaciones de crédito que realizare para atender necesidades de urgencia o emprender obras de utilidad o beneficio colectivo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-68', lawId: 'const-misiones', number: '68', title: '', text: `Toda ley especial que disponga o autorice gastos no previstos en el presupuesto deberá determinar el recurso especial correspondiente, salvo que responda a una extrema necesidad pública.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-69', lawId: 'const-misiones', number: '69', title: '', text: `El gobierno no podrá disponer de suma alguna del capital de las instituciones de crédito de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-70', lawId: 'const-misiones', number: '70', title: '', text: `Toda enajenación de bienes fiscales o municipales, compra, obra pública y demás contratos se hará por el sistema de subasta o licitación pública, bajo pena de nulidad, sin perjuicio de las responsabilidades emergentes. La ley u ordenanza, en su caso, reglamentará este principio y sus excepciones. Los funcionarios y empleados a sueldo del Estado no podrán intervenir como oferentes, apoderados o intermediarios en licitaciones públicas bajo pena de nulidad y cesantía.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-71', lawId: 'const-misiones', number: '71', title: '', text: `El régimen tributario de la Provincia se estructurará sobre las bases de la función económico-social de los impuestos y contribuciones. La igualdad, proporcionalidad y progresividad constituyen la base de los impuestos y de las cargas públicas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-72', lawId: 'const-misiones', number: '72', title: '', text: `Los artículos superfluos o suntuarios se gravarán más intensamente y los consumos esenciales de la población se desgravarán paulatinamente. Serán parcialmente desgravadas las utilidades reinvertidas en el proceso productivo y en la investigación técnico-científica hasta tanto se logre una tasa de inversión óptima. El impuesto directo se orientará preferentemente hacia la gravación de los ingresos en forma progresiva, pero estableciendo que la misma no impida el ahorro y la capitalización. El mismo criterio se aplicará en la transmisión gratuita de bienes, sobre todo en los medios rurales de explotación, y al patrimonio y renta mínimos que constituyan un bien individual familiar, los que podrán llegar a ser eximidos de cargas por períodos y en la forma que establezca la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-73', lawId: 'const-misiones', number: '73', title: '', text: `En una misma fuente no podrán superponerse gravámenes de igual naturaleza y categoría, aunque la superposición se opere entre impuestos nacionales, provinciales y municipales. La Provincia, a fin de evitar la múltiple imposición, convendrá con la Nación y municipalidades la forma de aplicación y percepción de los impuestos que le corresponde recaudar.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-74', lawId: 'const-misiones', number: '74', title: '', text: `La participación en la percepción de impuestos o contribuciones que corresponda a las municipalidades y organismos descentralizados les será entregada por los menos trimestralmente. Del incumplimiento de esta obligación serán responsables el gobernador y el ministro del ramo, sin perjuicio de la responsabilidad que incumba al contador de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-75', lawId: 'const-misiones', number: '75', title: '', text: `Todos los habitantes son admisibles en los empleos públicos sin más requisitos que la idoneidad, no habiendo para los extranjeros otras limitaciones que las establecidas en esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-76', lawId: 'const-misiones', number: '76', title: '', text: `No podrán ocupar cargos públicos los deudores de la Provincia que, ejecutados legalmente, no hubieren pagado sus deudas, los inhabilitados por sentencia y los quebrados fraudulentos no rehabilitados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-77', lawId: 'const-misiones', number: '77', title: '', text: `La Legislatura dictará el estatuto del empleado público que garantizará los siguientes derechos básicos: preferente admisión por concurso, estabilidad, ascenso, vacaciones, asistencia social, agremiación, pensión y jubilación móviles y todo lo que dignifique la carrera administrativa.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-78', lawId: 'const-misiones', number: '78', title: '', text: `No podrán acumularse en una persona dos o más empleos, así sean nacionales, provinciales o municipales, con excepción de los docentes y los de carácter profesional técnico en los casos y con las limitaciones que la ley establezca.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-79', lawId: 'const-misiones', number: '79', title: '', text: `El funcionario o empleado a quien se impute delito cometido en el ejercicio de su cargo está obligado a acusar judicialmente para vindicarse, bajo pena de su destitución, y gozará del beneficio de gratuidad procesal.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-80', lawId: 'const-misiones', number: '80', title: '', text: `La Provincia y sus agentes son responsables del daño que éstos causaren a terceros por mal desempeño en el ejercicio de sus funciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-81', lawId: 'const-misiones', number: '81', title: '', text: `La Provincia podrá ser ejecutada en la forma ordinaria si transcurrido un año de la fecha en que el fallo condenatorio hubiere quedado firme la Legislatura no arbitrare los recursos para efectuar el pago. Exceptúanse de esta disposición las rentas o bienes especiales afectados en garantía de una obligación de los servicios públicos. SEGUNDA`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-82', lawId: 'const-misiones', number: '82', title: '', text: `El Poder Legislativo de la Provincia será ejercido por una Cámara de Representantes elegida directamente por el pueblo, en la proporción de uno por cada doce mil habitantes o fracción que no baje de ocho mil quinientos, con arreglo a la población censada. Después de cada censo nacional o provincial, la ley determinará el número de habitantes a quienes ha de representar cada diputado, a fin de que en ningún caso el número total exceda de cuarenta ni sea menor de treinta.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-83', lawId: 'const-misiones', number: '83', title: '', text: `Para ser miembro de la Cámara de Representantes se requerirá haber cumplido la edad de veinticinco años, tener ciudadanía natural en ejercicio o legal después de cuatro años de obtenida; ser nativo de la Provincia, o tener dos años de residencia inmediata en ella.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-84', lawId: 'const-misiones', number: '84', title: '', text: `Los diputados durarán cuatro años en sus funciones y podrán ser reelegidos. La Cámara se renovará por mitades cada bienio, a cuyo efecto los electos para la primera Legislatura, luego que se reúnan, sortearán los que deben cesar en el primer período. Las vacantes no serán cubiertas cuando faltare menos de un año para el término del período correspondiente, a menos que alcancen la quinta parte del total de la Legislatura.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-85', lawId: 'const-misiones', number: '85', title: '', text: `Es incompatible el cargo de diputado con: 1. El de funcionario o empleado público a sueldo de la Nación, de las provincias o de las municipalidades, con excepción de la docencia y de las comisiones honorarias o eventuales, debiendo estas últimas ser aceptadas con el consentimiento de la Cámara. 2. El de funcionario o empleado dependiente de una empresa particular que se rija por concesiones de la Legislatura y tenga, por ese solo hecho, relaciones con los poderes públicos de la Provincia. 3. Todo otro cargo de carácter electivo, sea nacional, provincial o municipal. El diputado que haya aceptado algún cargo incompatible con el suyo, será separado de la representación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-86', lawId: 'const-misiones', number: '86', title: '', text: `No podrán celebrar contratos con la administración federal, provincial o municipal, ni patrocinar causas contra la Nación, provincias o municipios, ni defender intereses privados ante la administración pública. Tampoco podrán participar en empresas beneficiadas con privilegios o concesiones dadas por el Estado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-87', lawId: 'const-misiones', number: '87', title: '', text: `Los diputados prestarán en el acto de su incorporación juramento de desempeñar debidamente el cargo y de obrar en un todo de acuerdo con lo que prescribe esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-88', lawId: 'const-misiones', number: '88', title: '', text: `Los diputados no podrán ser acusados, interrogados judicialmente ni molestados por las opiniones que manifiesten o votos que emitan en el desempeño de su cargo. Gozarán de completa inmunidad en su persona desde el día de su elección hasta el cese. Tampoco podrán ser arrestados, excepto en el caso de ser sorprendidos in fraganti en la ejecución de un delito que merezca pena corporal, en el cual caso deberá darse cuenta de la detención dentro del plazo de tres días a la Cámara, la que al conocer el sumario podrá allanar el fuero del acusado con el voto de los dos tercios de sus miembros.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-89', lawId: 'const-misiones', number: '89', title: '', text: `Cuando se promueva acción penal contra un miembro de la Cámara, ésta podrá, luego de examinar el mérito del sumario en juicio público, con los dos tercios de votos de los miembros presentes, levantar los fueros y ponerlo a disposición de juez competente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-90', lawId: 'const-misiones', number: '90', title: '', text: `Con dos tercios de votos de la totalidad de sus miembros podrá corregir con multa, suspensión y aun con la expulsión de su seno, a cualquiera de sus miembros por la inasistencia reiterada y contumaz o mala conducta en el desempeño de sus funciones y removerlos por inhabilidad física o moral, sobrevinientes a su incorporación. Pero bastará la mayoría de uno sobre la mitad de los presentes para decidir de la renuncia que voluntariamente cualquiera hiciere de su cargo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-91', lawId: 'const-misiones', number: '91', title: '', text: `La Cámara tendrá autoridad para corregir, de acuerdo con los principios parlamentarios, con arrestos que no pasen de un mes, a toda persona de fuera de su seno que viole sus privilegios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-92', lawId: 'const-misiones', number: '92', title: '', text: `La Cámara dictará su reglamento, que no podrá modificar sobre tablas ni en un mismo día.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-93', lawId: 'const-misiones', number: '93', title: '', text: `La Cámara sancionará su presupuesto fijando el número de funcionarios y empleados que necesite y la forma en que debe proveerse dicha dotación. Esta ley no podrá ser vetada.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-94', lawId: 'const-misiones', number: '94', title: '', text: `Los diputados gozarán de una remuneración determinada por ley. En caso de ser aumentada, no podrá beneficiar a quienes votaron el aumento durante el período de su mandato.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-95', lawId: 'const-misiones', number: '95', title: '', text: `La Cámara podrá hacer concurrir al recinto de sesiones a los ministros del Poder Ejecutivo para pedirles los informes y explicaciones que estime convenientes, citándolos con tres días de anticipación por lo menos, salvo los casos de urgencia, comunicando en la citación los puntos sobre los cuales deberá informar. Podrá también la Cámara o sus comisiones pedir al Poder Ejecutivo y al Poder Judicial los datos e informes que estime necesarios y éstos están obligados a darles en el tiempo en que le sean solicitados. Esta facultad podrá ejercerla también cuando se trate de sesiones de prórroga o extraordinarias.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-96', lawId: 'const-misiones', number: '96', title: '', text: `La Cámara se reunirá sin que sea esencial ningún requisito de apertura. Sesionará todos los años en forma ordinaria desde el 1º de mayo hasta el 31 de octubre. Este término podrá ser prorrogado cuando así lo disponga la mayoría absoluta de sus miembros.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-97', lawId: 'const-misiones', number: '97', title: '', text: `Por motivos de interés público y urgente el Poder Ejecutivo podrá convocar a la Cámara a sesiones extraordinarias o convocarse ésta por sí misma cuando un tercio de sus miembros lo solicitare. En ambos supuestos se considerarán exclusivamente los asuntos que determinare la convocatoria. En caso de haber sido convocada por petición de sus miembros, la Cámara deberá decidir si la convocatoria se halla justificada.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-98', lawId: 'const-misiones', number: '98', title: '', text: `La Cámara no podrá sesionar sin la mayoría de los miembros que la componen, pero después de tres citaciones especiales consecutivas sin poderse reunir por falta de quórum podrá sesionar con la tercera parte de sus miembros, con excepción de los casos en que por esta Constitución se exija quórum especial. Las citaciones especiales a que se refiere este artículo se harán con un intervalo no menor de cuarenta y ocho horas a contar desde la emisión de las citaciones y en dichas sesiones no se podrán tratar otros asuntos que los determinados en el orden del día.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-99', lawId: 'const-misiones', number: '99', title: '', text: `Anualmente la Cámara de Representantes de la Provincia elegirá a pluralidad de votos su presidente y los vicepresidentes primero y segundo. Quien ejerza la presidencia tendrá voto y decidirá en caso de empate.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-100', lawId: 'const-misiones', number: '100', title: '', text: `Durante el receso de la Cámara de Representantes funcionará una Comisión Legislativa Permanente que intervendrá en los asuntos urgentes, las que estará presidida por el presidente de la Cámara y cuya composición y facultades se determinarán en el reglamento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-101', lawId: 'const-misiones', number: '101', title: '', text: `Corresponde a la Cámara de Representantes: 1. Aprobar o desechar los tratados con la Nación y con otras provincias. 2. Establecer los impuestos y contribuciones necesarios para atender los gastos de servicio de la administración, seguridad y bienestar general de la Provincia. 3. Fijar por un año o período superior hasta un máximo de tres, a propuesta del Poder Ejecutivo, el cálculo de recursos y el presupuesto de gastos. Si el Poder Ejecutivo no remitiere los proyecto de presupuestos y leyes de recursos para el ejercicio siguiente antes del 31 de julio, la Cámara podrá iniciar su estudio y sancionarlo tomando como base las leyes vigentes. Vencido el ejercicio administrativo sin que la Legislatura hubiere sancionado una nueva ley de gastos y recursos, se tendrán por prorrogadas las que hasta ese momento se encuentren en vigencia. 4. Legislar sobre el uso, disposición y enajenación de las tierras e inmuebles de propiedad provincial. 5. Calificar los casos de expropiación por causas de utilidad pública o interés general, determinando los fondos con que debe hacerse la indemnización previa. 6. Autorizar la Poder Ejecutivo, con los dos tercios de los miembros presentes, a contraer empréstitos o emitir fondos públicos con bases y objetos determinados, no pudiendo ser autorizado para equilibrar los gastos ordinarios de la administración. En ningún caso la totalidad de los servicios de los empréstitos comprometerán más de la cuarta parte de las rentas de la Provincia. Ni el numerario obtenido de los mismos, ni los fondos públicos que se emitan, podrán ser aplicados a otros objetos que los determinados por la ley de su creación. 7. Promover la colonización en las tierras fiscales o en los latifundios que no cumplan la función social de la propiedad; fomentar la producción, la industria y el comercio auspiciando el desarrollo de las empresas cuyo capital contribuya al bienestar general; propender a la formación de sociedades cooperativas; fomentar el incremento de las actividades agropecuarias; planificar una plantación forestal que persiga una racional explotación de sus bosques y la forestación y reforestación; auspiciar el turismo contemplando la finalidad social de su objetivo; facilitar los medios de transporte hacia los centros de consumo y puestos de embarque, mediante caminos, vías férreas y medios de transporte fluvial y aéreo, y, en general, desarrollar una política legislativa tendiente al bienestar social y a la felicidad de los habitantes de la Provincia. 8. Arreglar el pago de las deudas de la Provincia, dictar la ley orgánica del crédito público, autorizar el establecimiento y funcionamiento de las entidades bancarias. 9. Disponer la creación de villas, declarar ciudades y promover la construcción de obras públicas. 10. Acordar subsidios, con el voto de las dos terceras partes de sus miembros presentes, a las municipalidades. 11. Establecer la división política de la Provincia y los ejidos municipales, tomando por base la extensión, población y continuidad. 12. Acordar amnistías por delitos políticos, faltas o contravenciones previstas en la legislación provincial, excepto los de fraude electoral o contra la libertad de sufragio. 13. Crear o suprimir empleos para la mejor administración de la Provincia, determinando sus atribuciones y responsabilidades, evitando los excesos de la burocracia. 14. Dictar las leyes que aseguren y garanticen el ejercicio de los derechos sociales. 15. Dictar leyes sobre jubilaciones, retiros y pensiones para el personal de la administración provincial y municipal y aprobar los convenios que a tal fin pudieren celebrarse con la Nación u otras provincias y municipalidades. 16. Dictar la ley de elecciones generales para toda la Provincia según los principios enunciados en esta Constitución. 17. Dictar leyes relativas a la educación. 18. Acordar recompensas de estímulo. 19. Dictar códigos de procedimientos, rural y fiscal; leyes de organización de la administración de justicia, del Registro Civil, orgánica municipal, de tierras públicas, de bosques, viales y de expropiaciones, de régimen de los partidos políticos, de estatuto del empleado y del estatuto del docente. 20. Autorizar la cesión de tierras de la Provincia para objetos de utilidad pública, con el voto de los dos tercios de los miembros de la Cámara, cuando esa cesión importe abandono de jurisdicción o desmembramiento territorial, dentro de los límites prescriptos por la Constitución Nacional. En este caso la ley deberá ser ad referéndum. 21. Crear reparticiones autárquicas, pudiendo darles facultades para designar su personal y administrar los fondos que se les asigne, dentro de las prescripciones de la ley de creación. 22. Ejercer la legislación exclusiva sobre los servicios públicos de la Provincia establecidos fuera de la jurisdicción municipal. 23. Declarar intervenidos a los organismos municipales en los casos autorizados por esta Constitución. 24. Tomar juramento al gobernador y vicegobernador y sus reemplazantes en cada caso, concederles o negarles licencias para salir temporalmente del territorio de la Provincia, incluso de la capital por más de 15 días consecutivos, aceptar o rechazar sus renuncias. 25. Prestar o no acuerdo para el nombramiento de magistrados y funcionarios. 26. Elegir senadores nacionales y considerar sus renuncias cuando sean presentadas antes de su incorporación al Senado de la Nación. 27. Autorizar, aprobar o disponer la movilización de milicias por el Poder Ejecutivo en los casos del artículo 108 de la Constitución Nacional. 28. Dictar todas aquellas leyes necesarias para el mejor desempeño de las anteriores atribuciones y para todo asunto de interés público y general de la Provincia que por su naturaleza y objeto no corresponda privadamente al Congreso Nacional.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-102', lawId: 'const-misiones', number: '102', title: '', text: `Las leyes tendrán origen en la Cámara de Representantes, por iniciativa de uno o más de sus miembros o por proyectos del Poder Ejecutivo. Ningún proyecto de ley desechado totalmente por la Cámara podrá repetirse durante el año de su rechazo. En la sanción de las leyes se usará la siguiente fórmula: "La Cámara de Representantes de la Provincia sanciona con fuerza de ley".`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-103', lawId: 'const-misiones', number: '103', title: '', text: `Aprobado por la Cámara de Representantes un proyecto de ley, será pasado al Poder Ejecutivo a los efectos de su promulgación. Dentro del término de diez días de haberlo recibido de la Legislatura, el Poder Ejecutivo podrá devolverlo observado en todo o en parte. Si no lo hiciere, el proyecto quedará convertido en ley y deberá promulgarse y publicarse por el Poder Ejecutivo en el día inmediato al del vencimiento del plazo o publicarse, en su defecto, por orden del presidente de la Cámara.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-104', lawId: 'const-misiones', number: '104', title: '', text: `Desechado en todo o en parte un proyecto de ley por el Poder Ejecutivo, volverá con sus objeciones a la Legislatura y si ésta insiste en su sanción con el voto de la mayoría absoluta de sus miembros será ley y pasará al Poder Ejecutivo para su promulgación. No existiendo la mayoría citada para su insistencia ni mayoría para aceptar la modificación propuesta por el Poder Ejecutivo, no podrá repetirse en las sesiones de ese año. Vetado en parte un proyecto de ley el Poder Ejecutivo no podrá promulgarse la parte no vetada, excepto respecto de la ley general de presupuesto, que, en caso de ser vetada, sólo será reconsiderada en la parte observada, quedando el resto en vigencia. Si al tiempo de devolver el Poder Ejecutivo una ley observada la Cámara hubiere entrada en receso, ésta podrá pronunciarse acerca de la aceptación o no aceptación de las observaciones durante las sesiones de prórroga extraordinarias u ordinarias subsiguientes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-105', lawId: 'const-misiones', number: '105', title: '', text: `El Poder Ejecutivo será desempeñado por el gobernador de la Provincia, y en su defecto por el vicegobernador elegido al mismo tiempo y por igual período que aquél.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-106', lawId: 'const-misiones', number: '106', title: '', text: `Para ser elegido gobernador o vicegobernador se requiere ser argentino nativo o por opción, haber cumplido treinta años y tener tres de domicilio inmediato en la Provincia, si no hubiere nacido en ella, salvo en caso de ausencia por servicios prestados a la Nación o a la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-107', lawId: 'const-misiones', number: '107', title: '', text: `El gobernador y el vicegobernador serán elegidos a simple pluralidad de sufragios; durarán cuatro años en el ejercicio de sus funciones y cesarán en el mismo día que expire el período legal, sin que evento alguno pueda motivar su prorrogación ni tampoco que se les complete más tarde.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-108', lawId: 'const-misiones', number: '108', title: '', text: `Al tomar posesión de cargos el gobernador y vicegobernador prestarán juramento ante la Cámara de Representantes y en su defecto ante el Superior Tribunal de Justicia, de cumplir y hacer cumplir fielmente la Constitución y leyes de la Nación y de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-109', lawId: 'const-misiones', number: '109', title: '', text: `El gobernador y el vicegobernador gozarán de la retribución que la ley fije. Dicha retribución no podrá ser alterada hasta el término de su mandato.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-111', lawId: 'const-misiones', number: '111', title: '', text: `El gobernador y el vicegobernador en ejercicio de sus funciones residirán en la capital de la Provincia, no podrán ausentarse de ella por más de quince días sin permiso de la Legislatura y en ningún caso del territorio de la Provincia sin este requisito. La ausencia simultánea del gobernador y del vicegobernador de la capital por más de tres días y de la Provincia por cualquier tiempo, confiere de hecho el ejercicio del cargo a sus reemplazantes legales. Durante el receso de la Legislatura, sólo podrán ausentarse de la Provincia por motivos urgentes y por el tiempo estrictamente indispensable, previa autorización de la Comisión Legislativa Permanente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-112', lawId: 'const-misiones', number: '112', title: '', text: `En caso de ausencia temporal y simultánea del gobernador y vicegobernador, ejercerán el Poder Ejecutivo las autoridades de la Cámara de Representantes, por su orden, y hasta que cese la inhabilidad. En caso de acefalía el cargo de gobernador será ejercido interinamente por el presidente de la Cámara de Representantes, quien dentro del término de cinco días convocará a elecciones para reemplazarlo, siempre que faltare más de dos años para completar el período constitucional. Si faltare menos de dos años, la Cámara de Representantes convocada especialmente dentro del mismo plazo, procederá a elegir gobernador y vicegobernador por mayoría absoluta de la totalidad de sus miembros. En ambos supuestos la elección será para completar el período constitucional y no podrá recaer en la persona del presidente de la Cámara de Representantes. En caso de acefalía total por impedimento o renuncia del gobernador y sus substitutos legales, el Poder Ejecutivo será asumido por el presidente del Superior Tribunal de Justicia a los efectos de la convocatoria inmediata a elecciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-113', lawId: 'const-misiones', number: '113', title: '', text: `Si antes de asumir el cargo el ciudadano electo gobernador falleciere, renunciare o no pudiere ejercer el cargo, se procederá a una nueva elección.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-114', lawId: 'const-misiones', number: '114', title: '', text: `El gobernador y el vicegobernador gozarán de las mismas inmunidades que los diputados. Son incompatibles los cargos de gobernador y vicegobernador con cualquier empleo y el ejercicio de toda profesión.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-115', lawId: 'const-misiones', number: '115', title: '', text: `El gobernador y el vicegobernador no podrán ausentarse de la Provincia sin autorización de la Cámara de Representantes, hasta tres meses después de haber cesado en sus funciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-116', lawId: 'const-misiones', number: '116', title: '', text: `El gobernador es el jefe de la administración y representa a la Provincia en sus relaciones con los poderes públicos de la Nación y con las demás provincias y tiene los siguientes deberes y atribuciones: 1. Informar a la Cámara de Representantes al iniciarse cada período de sesiones ordinarias del estado general de la administración, del movimiento de fondos que se hubiere producido dentro o fuera del presupuesto general durante el ejercicio económico anterior y de las necesidades públicas y sus soluciones inmediatas. 2. Participar en la formación de las leyes con arreglo a la Constitución, teniendo el derecho de iniciarlas por proyectos presentados a la Legislatura y tomar parte en su discusión por sí, por medio del vicegobernador o de los ministros. 3. Votar total o parcialmente las leyes sancionadas por la Cámara de Representantes, en la forma dispuesta por esta Constitución dando los fundamentos de las observaciones que formule. 4. Presentar dentro de los tres primeros meses de iniciado el período de sesiones ordinarias el proyecto de ley de presupuesto general de la administración y de las reparticiones autárquicas, acompañado del plan de recursos. 5. Hacer recaudar las rentas de la Provincia, decretar su inversión con arreglo a la ley y dar a publicidad, por lo menos trimestralmente, el estado de la Tesorería. 6. Convocar a elecciones conforme a esta Constitución y leyes respectivas. 7. Convocar a sesiones extraordinarias a la Legislatura cuando lo exija un grave interés público, salvo el derecho de ésta para apreciar y decidir, después de reunida, sobre los fundamentos de la convocatoria. 8. Celebrar y firmar contratos con otras provincias para fines de administración de justicia, intereses económicos y trabajos de utilidad común con la aprobación del Poder Legislativo, dando cuenta oportunamente al Congreso Nacional. 9. Nombrar y remover a los ministros-secretarios y demás funcionarios y empleados de la administración, cuyos nombramientos no estén acordados a otro poder. 10*. Nombrar, con acuerdo de la Cámara de Representantes, con el voto de los dos tercios de la totalidad de sus miembros y en sesión pública, a los Magistrados del Superior Tribunal de Justicia. Nombrar, con acuerdo de la Cámara de Representantes, a los jueces inferiores, fiscales y defensores del Poder Judicial, en base a una propuesta vinculante de tres a cinco postulantes, seleccionada por el Consejo de la Magistratura. La composición, facultades y funcionamiento del Consejo serán establecidos por ley, para cuya sanción y reforma se requerirá el voto de los dos tercios de la totalidad de los miembros de la Cámara de Representantes. Nombrar, con acuerdo de la Cámara de Representantes, al Procurador General, al Fiscal de Estado, Contador, Subcontador, Tesorero, Subtesorero, miembros del Tribunal de Cuentas, Director General de Educación y vocales del Consejo General de Educación. 11. Nombrar y remover los funcionarios y empleados con las exigencias y formalidades legales. Durante el receso de la Cámara de Representantes los nombramientos que requieran acuerdos se harán "en comisión", con cargo de dar cuenta en los primeros quince días del período de sesiones ordinarias, bajo sanción de que si así no se hiciere los funcionarios cesarán en sus empleos. 12. Ejercer la policía de la Provincia. 13. Prestar inexcusablemente el auxilio de la fuerza pública a los tribunales de justicia, al presidente de la Cámara de Representantes, a las municipalidades y demás autoridades y funcionarios que por la Constitución o por la ley puedan hacer uso de ella. 14. Indultar o conmutar las penas impuestas, dentro de la jurisdicción provincial, previo informe favorable del Superior Tribunal de Justicia, excepto en los casos de delitos electorales y con respecto a los funcionarios sometidos al procedimiento del juicio político o del jurado de enjuiciamiento. 15. Ejercer la jurisdicción administrativa en el modo y forma que la ley determine. 16. Conceder pensiones y jubilaciones conforme a la ley de la materia. 17. Expedir decretos, instrucciones o reglamentos para la ejecución de las leyes. *10. Modificado por Ley 3651`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-117', lawId: 'const-misiones', number: '117', title: '', text: `El gobernador no puede expedir resoluciones ni decretos sin la firma de los ministros respectivos, salvo el nombramiento o remoción de éstos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-118', lawId: 'const-misiones', number: '118', title: '', text: `El gobernador o el vicegobernador, en su caso, y los ministros en los actos que legalicen con su firma o acuerden en común, son solidariamente responsables y pueden ser acusados ante la Cámara de Representantes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-119', lawId: 'const-misiones', number: '119', title: '', text: `El vicegobernador en tanto no reemplace al gobernador, sin perjuicio de las funciones que como colaborador directo de éste puedan corresponderle, tendrá además las de: 1. Asistir a los acuerdos de ministros, pudiendo suscribir los decretos que en los mismos se elaboren. 2. Mantener relaciones con los demás poderes del Estado a fin de establecer una armónica coordinación con los mismos. 3. Dedicar preferente atención a los problemas agrarios y los que, en general, afecten al interior de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-120', lawId: 'const-misiones', number: '120', title: '', text: `El despacho de los negocios administrativos de la Provincia estará a cargo de ministros-secretarios, cuyo número y funciones se determinará por ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-121', lawId: 'const-misiones', number: '121', title: '', text: `Para ser nombrado ministro se requieren las mismas condiciones que para ser elegido diputado y no ser pariente dentro del cuarto grado de consanguinidad y segundo de afinidad con el gobernador. Gozarán de un sueldo establecido por la ley, el que no podrá ser alterado durante el ejercicio de sus funciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-122', lawId: 'const-misiones', number: '122', title: '', text: `Los ministros despacharán de acuerdo con el gobernador todos los asuntos de su competencia y refrendarán con su firma las resoluciones de éste, sin cuyo requisito carecerán de validez. Podrán, no obstante, decidir por sí solos todo lo referente al régimen interno de sus respectivos departamentos y dictar resoluciones de trámite.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-123', lawId: 'const-misiones', number: '123', title: '', text: `Son responsables de todas las órdenes y resoluciones que autoricen, sin que puedan eximirse de responsabilidad por haber procedido en virtud de orden del gobernador.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-124', lawId: 'const-misiones', number: '124', title: '', text: `Dentro de los treinta días posteriores a la apertura del período de sesiones, los ministros presentarán a la Cámara de Representantes una memoria detallada del estado de la administración correspondiente a sus respectivos departamentos, sugiriendo las reformas e iniciativas que consideren necesarias.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-125', lawId: 'const-misiones', number: '125', title: '', text: `Los ministros deben asistir a las sesiones de la Cámara de Representantes cuando fueren llamados por ella a suministrar informes. Pueden también hacerlo cuando lo crean conveniente y tomar parte en sus discusiones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-126', lawId: 'const-misiones', number: '126', title: '', text: `Los ministros están obligados a remitir a la Cámara de Representantes las informaciones, memorias y demás datos que ésta les solicite sobre lo relativo a los asuntos de sus respectivos departamentos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-127', lawId: 'const-misiones', number: '127', title: '', text: `Es incompatible el cargo de ministro con cualquier empleo o el ejercicio de toda profesión.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-128', lawId: 'const-misiones', number: '128', title: '', text: `El Fiscal de Estado es el encargado de defender el patrimonio del fisco. Será parte legítima en los juicios contencioso-administrativos y en todos aquellos en que se controviertan los intereses de la Provincia. Tendrá también personería para defender la nulidad o inconstitucionalidad de la ley, decreto, reglamento, contrato o resolución que pueda perjudicar los intereses fiscales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-129', lawId: 'const-misiones', number: '129', title: '', text: `Para ser Fiscal de Estado se requieren las mismas condiciones que para ser juez de primera instancia. Será nombrado por el Poder Ejecutivo con acuerdo de la Cámara de Representantes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-130', lawId: 'const-misiones', number: '130', title: '', text: `La ley determinará las condiciones requeridas para ser designado contador, subcontador, tesorero o subtesorero de la Provincia como también sus funciones, duración y responsabilidades. Serán nombrados por el Poder Ejecutivo con acuerdo de la Cámara de Representantes, siendo tales cargos incompatibles con cualquier otro empleo y con el ejercicio de toda profesión, excepto de la docencia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-131', lawId: 'const-misiones', number: '131', title: '', text: `Sin perjuicio de lo que disponga la ley, la Contaduría no prestará su conformidad a pago alguno que no esté autorizado por la ley general de presupuesto o por leyes especiales. La Tesorería no podrá ejecutar pago alguno que no haya sido previamente autorizado por la Contaduría.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-132', lawId: 'const-misiones', number: '132', title: '', text: `El Tribunal de Cuentas estará compuesto por un presidente, abogado, y dos vocales, contadores públicos, todos inamovibles, nombrados por el Poder Ejecutivo con acuerdo de la Cámara de Representantes. No podrán tener ningún otro empleo ni ejercer profesión.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-133', lawId: 'const-misiones', number: '133', title: '', text: `Sin perjuicio de lo que disponga la ley, el Tribunal tendrá las siguientes atribuciones: 1. Examinar las cuentas de percepción e inversión de las rentas públicas, tanto provinciales como municipales y de reparticiones autárquicas; aprobarlas o desaprobarlas y, en este último caso, indicar el funcionario o funcionarios responsables, como también el monto y la causa de los alcances respectivos. A tal fin los poderes públicos, las municipalidades, y los que administren los caudales de la Provincia, estarán obligados a remitir anualmente las cuentas documentadas de los dineros percibidos e invertidos, para su aprobación o desaprobación. El Tribunal se pronunciará en el término de un año de la presentación; de los contrario se tendrán por aprobadas sin perjuicio de la responsabilidad de los miembros del Tribunal. 2. Inspeccionar las oficinas provinciales y municipales, que administren fondos públicos y tomar las medidas necesarias para prevenir cualquier irregularidad, en la forma y con arreglo al procedimiento que determine la ley. 3. Fiscalizar las cuentas de las instituciones privadas que reciban subsidios del Estado provincial.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-134', lawId: 'const-misiones', number: '134', title: '', text: `La ley organizará la Policía de Seguridad y Defensa, estableciendo sus funciones, deberes y responsabilidades, de acuerdo con esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-135', lawId: 'const-misiones', number: '135', title: '', text: `La Policía de Seguridad y Defensa tendrá jurisdicción exclusiva en toda la Provincia, y ésta no podrá admitir en su territorio otras fuerzas similares nacionales que las de seguridad y custodia de fronteras o aquellas a cuya admisión se obligue mediante leyes convenios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-136', lawId: 'const-misiones', number: '136', title: '', text: `El Poder Judicial de la Provincia será ejercido por un Superior Tribunal de Justicia compuesto de un número impar de magistrados y por los demás tribunales inferiores que la ley establezca.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-137', lawId: 'const-misiones', number: '137', title: '', text: `La ley determinará el orden jerárquico y la competencia, así como las incompatibilidades, las obligaciones y las responsabilidades de los miembros del Poder Judicial.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-138', lawId: 'const-misiones', number: '138', title: '', text: `Para ser magistrado del Superior Tribunal de Justicia o procurador general se requieren: ser ciudadano nativo o naturalizado con diez años de ejercicio en la ciudadanía, tener título de abogado expedido por universidad nacional o extranjera legalmente admitido por la Nación, treinta años de edad y seis en el ejercicio activo de la profesión de abogado o de la magistratura. Para ser miembro o fiscal de cámara bastarán cuatro años. La Ley establecerá los requisitos para ocupar los demás cargos judiciales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-139', lawId: 'const-misiones', number: '139', title: '', text: `Para ser juez letrado de primera instancia se requiere: ciudadanía, tener más de veinticinco años y ser abogado con tres años de ejercicio.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-140', lawId: 'const-misiones', number: '140', title: '', text: `Los magistrados del Superior Tribunal de Justicia y de los tribunales inferiores, así como los funcionarios judiciales que requieran acuerdo legislativo para su designación, son inamovibles y conservarán sus respectivos cargos mientras observan buena conducta y cumplan con sus obligaciones. Su retribución será establecida por ley y no podrá ser disminuida. No podrán ser trasladados ni ascendidos sin su consentimiento y solamente podrán ser removidos en la forma que se determina en esta Constitución. No podrán ser acusados, interrogados judicialmente ni molestados por las opiniones que emitan en sus fallos, resoluciones o dictámenes, ni arrestado, excepto en el caso de ser sorprendidos in fraganti en la ejecución de un delito que merezca pena corporal.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-141', lawId: 'const-misiones', number: '141', title: '', text: `En ningún caso el gobernador de la Provincia u otro funcionario del Poder Ejecutivo podrá ejercer funciones judiciales, arrogarse el conocimiento de las causas pendientes o restablecer las fenecidas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-142', lawId: 'const-misiones', number: '142', title: '', text: `El ministerio público es órgano del Poder Judicial.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-143', lawId: 'const-misiones', number: '143', title: '', text: `El Superior Tribunal de Justicia y los demás tribunales inferiores de la Provincia aplicarán esta Constitución como ley suprema con relación a leyes locales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-144', lawId: 'const-misiones', number: '144', title: '', text: `Corresponde al Poder Judicial el conocimiento y decisión de las causas que versen sobre puntos regidos por esta Constitución, por los tratados que celebre la Provincia y por las leyes; de las causas que se susciten contra los funcionarios y empleados que no estén sujetos a juicio político ni al jurado de enjuiciamiento y de las regidas por los códigos enumerados en el artículo 67, inciso 11 de la Constitución Nacional según que las cosas o personas caigan bajo la jurisdicción provincial.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-145', lawId: 'const-misiones', number: '145', title: '', text: `El Superior Tribunal de Justicia tiene en materia judicial las siguientes atribuciones, sin perjuicio de las demás que le confiere a la ley conforme a su función y jerarquía. 1. Ejerce jurisdicción originaria y por apelación para conocer y resolver sobre la constitucionalidad de las leyes, decretos, ordenanzas, resoluciones o reglamentos que estatuyan sobre materia regida por esta Constitución. 2. Conoce y resuelve originariamente en los conflictos de jurisdicción y competencia entre los poderes públicos de la Provincia o de sus diversas ramas y en los que se susciten entre los tribunales de justicia. 3. Conoce y resuelve originariamente en lo contencioso-administrativo de acuerdo a lo que establezca la ley de la materia, pudiendo mandar cumplir directamente su sentencia por las oficinas, funcionarios o empleados respectivos. Si la autoridad administrativa no lo hiciere dentro de los sesenta días de notificada, incurre en responsabilidad por su incumplimiento. 4. Conoce y resuelve en los recursos extraordinarios que la ley de procedimientos acuerde contra sentencias definitivas. 5. Conoce y resuelve en las recusaciones de sus vocales y en las quejas por denegación o retardo de justicia contra los miembros de las cámaras de apelaciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-146', lawId: 'const-misiones', number: '146', title: '', text: `En materia administrativa y sin perjuicio de las demás que la ley otorgue, tiene las siguientes atribuciones. 1. Dicta su reglamento interno y ejerce la superintendencia de toda la administración de justicia. 2. Remite anualmente al Poder Ejecutivo y por su conducto a la Legislatura, una memoria sobre el estado y necesidad de la administración de justicia, pudiendo proponer en forma de proyectos las reformas de procedimientos y organización que tiendan a mejorarla. 3. Nombra y remueve directamente a los secretarios y empleados del tribunal, y a propuesta de los jueces y funcionarios del ministerio público, al personal de sus respectivas dependencias. 4. Presenta anualmente al Poder Ejecutivo el presupuesto de gastos de la administración de justicia a fin de ser incluido en el presupuesto general de la Provincia. 5. Dispone y administra sus bienes y los fondos asignados por la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-147', lawId: 'const-misiones', number: '147', title: '', text: `El Poder Judicial dispondrá de la fuerza pública para el cumplimiento de sus decisiones. La Legislatura propenderá a la creación y estructuración de la policía judicial, integrada por un cuerpo de funcionarios inamovibles, con capacitación técnica, exclusivamente dependiente del Poder Judicial.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-148', lawId: 'const-misiones', number: '148', title: '', text: `La ley establecerá orgánicamente la justicia de paz en todas las ciudades y pueblos de la Provincia, sobre la base del procedimiento verbal y actuado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-149', lawId: 'const-misiones', number: '149', title: '', text: `Se propenderá a establecer la justicia de paz letrada en la capital de la Provincia y ciudades donde su importancia lo requiera. Los jueces de paz letrados serán nombrados de acuerdo con lo dispuesto por el artículo 116, inciso 10, de esta Constitución y equiparados a los de primera instancia en cuanto a jerarquía, estabilidad y prerrogativas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-150', lawId: 'const-misiones', number: '150', title: '', text: `Los jueces de paz no letrados serán nombrados por el Superior Tribunal de Justicia de una terna propuesta por la autoridad municipal local y ejercerán sus funciones judiciales con la competencia que la ley determina.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-151', lawId: 'const-misiones', number: '151', title: '', text: `El gobernador, el vicegobernador y sus reemplazantes legales y los magistrados del Superior Tribunal de Justicia pueden ser denunciados por cualquier habitante de la Provincia ante la Cámara de Representantes por incapacidad física o mental sobreviniente, por delito en el desempeño de sus funciones o falta de cumplimiento de los deberes correspondientes a sus cargos o por delitos comunes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-152', lawId: 'const-misiones', number: '152', title: '', text: `La Legislatura en su primera sesión ordinaria se dividirá en dos salas a los efectos del juicio político, realizándose un sorteo proporcional y de acuerdo a la integración política de la Cámara. La primera tendrá a su cargo la acusación y la segunda el juzgamiento, ambas presididas por miembros elegidos de su seno.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-153', lawId: 'const-misiones', number: '153', title: '', text: `La sala acusadora elegirá anualmente por simple mayoría, en la misma sesión, una comisión de investigación compuesta de cinco miembros. Dicha comisión tendrá por objeto investigar la verdad de los hechos denunciados, teniendo para ese efecto las más amplias facultades.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-154', lawId: 'const-misiones', number: '154', title: '', text: `La comisión terminará sus diligencias en el término perentorio de treinta días y presentará dictamen a la sala acusadora, la que lo aceptará o rechazará, necesitándose dos tercios de votos de los miembros presentes cuando el dictamen fuere favorable a la acusación, y desde ese momento quedará el acusado suspendido en el ejercicio de sus funciones y sin goce de sueldo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-155', lawId: 'const-misiones', number: '155', title: '', text: `Admitida la acusación por la sala acusadora, ésta nombrará una comisión de tres miembros para que la sostenga ante la segunda sala constituida en tribunal de sentencia, previo juramento especial, en cada caso, de sus miembros.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-156', lawId: 'const-misiones', number: '156', title: '', text: `Entablada la acusación por sala acusadora, el tribunal de sentencia procederá a conocer la causa que fallará en el término de treinta días. El juicio será oral y público y se garantizará la defensa y el descargo del acusado. Si vencido dicho término no se hubiere dictado sentencia, el acusado volverá al ejercicio de sus funciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-157', lawId: 'const-misiones', number: '157', title: '', text: `Ningún acusado podrá ser declarado culpable sino por el voto de los dos tercios de la totalidad de los miembros de la segunda sala. La votación será nominal, registrándose en el acta el voto que recaiga sobre cada uno de los cargos que contenga la acusación. El fallo no tendrá más efecto que destituir al acusado, quedando siempre sujeto a la acusación, juicio o condena, conforme a la legislación represiva común. Una ley especial determinará las demás normas para esta clase de juicios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-158', lawId: 'const-misiones', number: '158', title: '', text: `Los miembros del Poder Judicial y los funcionarios no sujetos al juicio político y que requieran acuerdo de la Legislatura para su nombramiento, podrán ser acusados por cualquier habitante y por las mismas causas del artículo 151 ante un jurado de enjuiciamiento, que estará integrado por el Presidente del Superior Tribunal, dos ministros de éste, dos legisladores y dos abogados de la matrícula.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-159', lawId: 'const-misiones', number: '159', title: '', text: `La ley reglamentará el procedimiento que ante él debe observarse, determinando el modo y la forma como deben ser nombrados los miembros componentes del jurado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-160', lawId: 'const-misiones', number: '160', title: '', text: `El acusado continuará en el ejercicio de sus funciones, si el jurados no resolviere lo contrario. El fallo deberá expedirse dentro de los sesenta días a contar desde la admisión de la demanda, bajo pena de nulidad y tendrá el mismo alcance que el finado en el artículo 157 de esta Constitución. El jurado se pronunciará siempre en pleno y por mayoría absoluta de sus miembros, y dará su veredicto con arreglo a derecho. Todas las garantías y derechos reconocidos por esta Constitución y la Nacional para el juicio de naturaleza penal, son de aplicación obligatoria. La ley no podrá restringir el derecho del denunciante mediante impuestos, fianzas, cauciones, gravámenes o requisitos no previstos en esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-161', lawId: 'const-misiones', number: '161', title: '', text: `El municipio gozará de autonomía política, administrativa y financiera, ejerciendo sus funciones con independencia de todo otro poder.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-162', lawId: 'const-misiones', number: '162', title: '', text: `La ley establecerá tres categorías de municipios, de acuerdo al número de sus habitantes. El gobierno de los municipios de primera y segunda categorías se ejercerá por una rama ejecutiva y otra deliberativa. Los municipios de tercera categoría, por comisiones de fomento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-163', lawId: 'const-misiones', number: '163', title: '', text: `Todas las autoridades municipales son electivas en forma directa. Los intendentes, a simple pluralidad de sufragios; los concejales y los miembros de las comisiones de fomento, por el sistema de representación proporcional.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-164', lawId: 'const-misiones', number: '164', title: '', text: `Serán electores los ciudadanos del municipio que estén inscriptos en el padrón provincial y los extranjeros, de ambos sexos, que se inscriban en el registro municipal, los que deberán tener más de dieciocho años de edad, saber leer y escribir en idioma nacional, ejercer actividad lícita, tener tres años de residencia permanente en el municipio y acreditar además algunas de esta condiciones: 1. Ser contribuyente directo. 2. Tener cónyuge o hijo argentino. La ley establecerá la forma en que deberá efectuarse el registro especial de extranjeros.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-165', lawId: 'const-misiones', number: '165', title: '', text: `Los electores del municipio tendrán los derechos de iniciativa, referéndum y destitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-166', lawId: 'const-misiones', number: '166', title: '', text: `Los conflictos que se planteen entre los municipios y la Provincia serán resueltos en única instancia por el Superior Tribunal de Justicia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-167', lawId: 'const-misiones', number: '167', title: '', text: `Son recursos municipales, sin perjuicio de los demás que la ley establezca: 1. El impuesto a la propiedad inmobiliaria y a las actividades lucrativas, en concurrencia con la Provincia y en la forma que la ley determine. 2. Las tasas y patentes. 3. Las contribuciones por mejoras. 4. Las multas por contravenciones a sus disposiciones y todos los demás recursos que la ley atribuya a los municipios. 5. Los empréstitos y demás operaciones de crédito.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-168', lawId: 'const-misiones', number: '168', title: '', text: `La Provincia sólo podrá intervenir los organismos municipales: 1. En caso de acefalía total, para asegurar la inmediata constitución de sus autoridades. 2. Cuando no cumpliere con los servicios de empréstitos o si de tres ejercicios sucesivos resultare un déficit susceptible de comprometer su estabilidad financiera. 3. Para normalizar la situación institucional.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-169', lawId: 'const-misiones', number: '169', title: '', text: `La intervención se hará en virtud de ley, por tiempo determinado, con fines a restablecer su normal funcionamiento y convocar a elecciones dentro de un plazo no mayor de sesenta días. Si la Cámara de Representantes se encontrare en receso, el Poder Ejecutivo podrá decretar la intervención, ad referéndum de lo que ésta resuelva, a cuyo efecto, por el mismo decreto, deberá convocarla a sesiones extraordinarias. Durante el tiempo que dure la intervención, el comisionado atenderá exclusivamente los servicios municipales ordinarios, con arreglo a las ordenanzas vigentes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-170', lawId: 'const-misiones', number: '170', title: '', text: `Los municipios comprendidos en la primera categoría podrán dictarse sus respectivas cartas orgánicas para su gobierno, de acuerdo a los principios contenidos en esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-171', lawId: 'const-misiones', number: '171', title: '', text: `Son atribuciones y deberes de los municipios: 1. Convocar a elecciones municipales. 2. Sancionar anualmente su presupuesto de gastos y su cálculo de recursos. 3. Entender en todo lo relativo a edificación, tierras fiscales municipales, abastecimiento, sanidad, asistencia social, espectáculos públicos, costumbres y moralidad, servicios públicos urbanos, reglamentación y habilitación de las vías públicas, paseos, cementerios y demás lugares de su dominio. 4. Establecer impuestos, tasas, contribuciones y formas de percibirlos. 5. Dar a publicidad trimestralmente el estado de sus ingresos y gastos, anualmente el balance general, y una memoria sobre la labor desarrollada dentro de los treinta días de vencido el ejercicio. 6. Contraer empréstitos para obras señaladas de mejoramiento, con dos tercios de votos de la totalidad de los miembros del Concejo. En ningún caso el servicio de la totalidad de los empréstitos podrá comprometer más de la cuarta parte de la renta, ni el fondo amortizante aplicarse a otros fines. 7. Enajenar en subasta pública y gravar los bienes municipales con dos tercios de votos de la totalidad de los miembros del Concejo. 8. Nombrar al personal de su dependencia y removerlo, previo sumario. 9. Realizar convenios de mutuo interés con otros entes de derecho público o privado. 10. Contratar, previa licitación, las obras que estime convenientes. 11. Fomentar la instrucción pública y la cultura artística, intelectual y física. 12. Dictar todas las ordenanzas y reglamentos dentro de las atribuciones conferidas por esta Constitución y por la ley orgánica de las municipalidades.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-172', lawId: 'const-misiones', number: '172', title: '', text: `Esta Constitución puede ser reformada en todo o en cualquiera de sus partes. La necesidad de la reforma debe ser declarada por la Cámara de Representantes con el voto de las dos terceras partes del total de sus miembros, determinando si la reforma será total o parcial pero ésta no se efectuará sino por una Convención Constituyente convocada al efecto, salvo lo dispuesto en el capítulo segundo de este título.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-173', lawId: 'const-misiones', number: '173', title: '', text: `Declarada por la Legislatura la necesidad de la reforma total o parcial, sin formalidad ulterior el Poder Ejecutivo convocará a elección de convencionales dentro del plazo que la misma ley fijará.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-174', lawId: 'const-misiones', number: '174', title: '', text: `La Convención se compondrá de tantos miembros cuantos sean los que formen la Cámara de Representantes y serán elegidos por el sistema de representación proporcional.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-175', lawId: 'const-misiones', number: '175', title: '', text: `Para ser convencional se requieren las mismas condiciones que para ser miembro de la Cámara de Representantes y gozarán de las mismas inmunidades mientras ejerzan sus funciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-176', lawId: 'const-misiones', number: '176', title: '', text: `El cargo de convencional es compatible con cualquier otro cargo público nacional o provincial que no sea el de gobernador, vicegobernador, jefe de policía o del departamento ejecutivo de los organismos municipales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-177', lawId: 'const-misiones', number: '177', title: '', text: `La Convención se reunirá dentro de los treinta días en que el tribunal electoral haya proclamado a los electos, y podrá sesionar con la tercera parte de sus miembros. Tendrá facultad para fijar el plazo de su cometido, que no podrá exceder del término de un año, transcurrido el cual caducará en su mandato; dictar su propio reglamento; nombrar su personal; confeccionar su presupuesto y aprobar sus inversiones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-178', lawId: 'const-misiones', number: '178', title: '', text: `La enmienda o reforma de un solo artículo podrá ser sancionada por el voto de los dos tercios de la totalidad de los miembros de la Cámara de Representantes y el sufragio afirmativo del pueblo de la Provincia, convocado al efecto en oportunidad de la primera elección de carácter provincial que se realice, en cuyo caso la enmienda o reforma quedará incorporada al texto constitucional. Reformas o enmiendas de esta naturaleza no podrán llevarse a cabo sino con intervalo de dos años.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-179', lawId: 'const-misiones', number: '179', title: '', text: `Para que un referéndum se considere válido, se requiere que los votos emitidos hayan sobrepasado el cincuenta por ciento de los electores inscriptos en el registro cívico provincial. Firmantes Adonai Enrique Vieira Convencional Constituyente Mario Losada, Presidente de la H. Convención Constituyente CLAUSULAS TRANSITORIAS`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-10', lawId: 'const-misiones', number: '10', title: '', text: `Una comisión compuesta por el señor presidente y dos señores convencionales, revisarán la fidelidad del registro del texto de esta Constitución hecho lo cual, la firmarán el presidente, el convencional secretario y los señores convencionales que deseen hacerlo y, sellada con el sello de la Convención, se entregará el original al Superior Tribunal de Justicia de la Provincia y se remitirán copias a los poderes nacionales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-11', lawId: 'const-misiones', number: '11', title: '', text: `La presente Constitución regirá a partir del día de la fecha.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-misiones-art-12', lawId: 'const-misiones', number: '12', title: '', text: `Téngase por Ley Fundamental de la Provincia de Misiones. Regístrese y publíquese para que se cumpla. Firmantes Adonai Enrique Vieira Convencional Constituyente Mario Losada, Presidente de la H. Convención Constituyente Volver Acerca de esta norma Acerca de esta norma Resumen de la normativa Normativa Esta norma es complementada o modificada por 1 norma Buscador de normativa /** * Controla el status del componente . * @summary Según el _media query_ lo imprime abierto o cerrado. * @returns {undefined} */ const panelMenu = () => { const details = document.querySelectorAll(".device-panel-menu"); if (window.innerWidth >= 991) { details.forEach((e) => e.setAttribute("open", true)); } else if (window.innerWidth e.removeAttribute("open")); } }; document.addEventListener("DOMContentLoaded", panelMenu); window.addEventListener('resize', panelMenu, true); @media (min-width: 992px) { aside.col-md-4 { position: -webkit-sticky; position: sticky; /* Aumentamos a 130px para que baje lo suficiente y se vea el título */ top: 130px; z-index: 10; align-self: flex-start; height: auto; } } /* Si quieres ser más preciso cuando NO estás logueado (sin barra negra) */ body:not(.logged-in) aside.col-md-4 { top: 20px; } /* Cuando SÍ hay barra de administración */ body.logged-in aside.col-md-4 { top: 130px; } Trámites Turnos Trámites a distancia Atención a la ciudadanía Acerca de la República Argentina Nuestro país Leyes argentinas Organismos Mapa del Estado Acerca de Argentina.gob.ar Acerca de este sitio Términos y condiciones Sugerencias Los contenidos de Argentina.gob.ar están licenciados bajo Creative Commons Atribución 4.0 Internacional --> Scroll hacia arriba`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
];

